class Solution:
    def gridGame(self, grid):
        n = len(grid[0])
        best = None
        for i in range(n):
            g = [row[:] for row in grid]
            for c in range(0, i + 1):
                g[0][c] = 0
            for c in range(i, n):
                g[1][c] = 0
            worst_second = 0
            for j in range(n):
                total = sum(g[0][0:j + 1]) + sum(g[1][j:n])
                if total > worst_second:
                    worst_second = total
            if best is None or worst_second < best:
                best = worst_second
        return best

