var gridGame = function(grid) {
    const top = grid[0], bottom = grid[1];
    const n = top.length;
    const topSum = top.reduce((a, b) => a + b, 0);
    let bottomPrefix = 0;
    let runningTop = 0;
    let best = null;
    for (let i = 0; i < n; i++) {
        runningTop += top[i];
        const topSuffix = topSum - runningTop;
        const second = Math.max(topSuffix, bottomPrefix);
        if (best === null || second < best) best = second;
        bottomPrefix += bottom[i];
    }
    return best;
};
